mapper.select:
SELECT jf.DWDM AS dwdm, jf.dept_id AS deptId, jf.jsbj AS jsbj, jf.cbjthbj AS cbjthbj, COUNT(jf.djxh) AS jfbs, COUNT(DISTINCT jf.djxh) AS jfhs, SUM(jf.YBTSE) AS ybtse, SUM(jf.YFJE) AS yfje, SUM(jf.GKZFJE) AS gkzfje, SUM(jf.GJTHJE) AS gjthje, SUM(jf.jcghje) AS jcghje, SUM(jf.cbjje) AS cbjje, SUM(jf.HYGHJE) AS hyghje, SUM(jf.xjghje) AS xjghje, SUM(jf.SJGHJE) AS sjghje, SUM(jf.SZGHJE) AS szghje, SUM(jf.QGGHJE) AS qgghje, SUM(jf.sdsje) AS sdsje, SUM(jf.swjgje) AS swjgje FROM xwqyjf jf
AND jf.DWDM = #{req.dwdm}
AND jf.dept_id = #{req.deptId}
AND jf.NSRMC LIKE CONCAT('%', #{req.nsrmc}, '%')
GROUP BY jf.DWDM, jf.dept_id, jf.jsbj, jf.cbjthbj

SELECT jf.DWDM AS dwdm, jf.dept_id AS deptId, jf.shxydm AS shxydm, jf.nsrmc AS nsrmc, jf.jsbj AS jsbj, jf.cbjthbj AS cbjthbj, COUNT(jf.djxh) AS jfbs, SUM(jf.YBTSE) AS ybtse, SUM(jf.YFJE) AS yfje, SUM(jf.GKZFJE) AS gkzfje, SUM(jf.GJTHJE) AS gjthje, SUM(jf.jcghje) AS jcghje, SUM(jf.cbjje) AS cbjje, SUM(jf.HYGHJE) AS hyghje, SUM(jf.xjghje) AS xjghje, SUM(jf.SJGHJE) AS sjghje, SUM(jf.SZGHJE) AS szghje, SUM(jf.QGGHJE) AS qgghje, SUM(jf.sdsje) AS sdsje, SUM(jf.swjgje) AS swjgje FROM xwqyjf jf
AND jf.DWDM = #{req.dwdm}
AND jf.dept_id = #{req.deptId}
AND jf.NSRMC LIKE CONCAT('%', #{req.nsrmc}, '%')
GROUP BY jf.DWDM, jf.dept_id, jf.shxydm, jf.nsrmc, jf.jsbj, jf.cbjthbj
